import json
import urllib.request
import sys

def fetch_file(repo, path, revision="HEAD"):
    """Fetch file content from Sourcegraph GraphQL API"""
    query = {
        "query": f"""
        query {{
            repository(name: "{repo}") {{
                commit(rev: "{revision}") {{
                    blob(path: "{path}") {{
                        content
                    }}
                }}
            }}
        }}
        """
    }

    req = urllib.request.Request(
        "https://sourcegraph.sourcegraph.com/api/graphql",
        data=json.dumps(query).encode('utf-8'),
        headers={"Content-Type": "application/json"}
    )

    try:
        with urllib.request.urlopen(req) as response:
            result = json.loads(response.read().decode('utf-8'))
            if 'data' in result and result['data']['repository']:
                commit = result['data']['repository']['commit']
                if commit and commit['blob']:
                    return commit['blob']['content']
    except Exception as e:
        print(f"Error fetching {path}: {e}", file=sys.stderr)

    return None

